queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?feature_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFeatures ?child ; p:hasOnboard_Entertainment_System ?parent . } GROUP BY ?child }
  ?child p:feature_name ?feature_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Onboard_Entertainment_System } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?feature_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFeatures ?child ; p:hasOnboard_Entertainment_System ?parent . } GROUP BY ?child }
  ?child p:feature_name ?feature_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Onboard_Entertainment_System } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?airline ?feature_name WHERE {
  ?onboard_entertainment_system_features a :Onboard_Entertainment_System_Features .
  ?features a :Features .
  ?onboard_entertainment_system_features p:hasFeatures ?features .
  ?onboard_entertainment_system a :Onboard_Entertainment_System .
  ?onboard_entertainment_system_features p:hasOnboard_Entertainment_System ?onboard_entertainment_system .
  ?onboard_entertainment_system p:airline ?airline .
  ?features p:feature_name ?feature_name .
} }
}
